mapper.update:
update cmp_bankaccount_realtimebalance a set a.banktype = (
    select b.bank as banktype from `${schema}`.org_fin_bankacct b
    where b.id = a.enterprisebankaccount
) where a.banktype is null;

update cmp_bankreconciliation a set a.banktype = (
    select b.bank as banktype from `${schema}`.org_fin_bankacct b
    where b.id = a.bankaccount
) where a.banktype is null;

update cmp_bankelectronicreceipt a set a.banktype = (
    select b.bank as banktype from `${schema}`.org_fin_bankacct b
    where b.id = a.enterprisebankaccount
) where a.banktype is null;

update cmp_bankdealdetail a set a.banktype = (
    select b.bank as banktype from `${schema}`.org_fin_bankacct b
    where b.id = a.enterprisebankaccount
) where a.banktype is null;
